const fields = $json.fields || {};

function text(value) {
  if (Array.isArray(value)) return value.join('\n');
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function arr(value) {
  if (Array.isArray(value)) return value;
  if (!value) return [];
  return [value];
}

const articleRecordId = $json.id;

const category = text(fields['Category']);
const baadPublishCategories = arr(fields['BAAD Publish Categories']).filter(Boolean);
const fallbackCategories = baadPublishCategories.length
  ? baadPublishCategories
  : category
    ? [category]
    : [];

return {
  articleRecordId,
  title: text(fields['Title']),
  dek: text(fields['Dek']),
  sourceBodySummary: text(fields['Source Body / Summary']),
  sourceOutlet: text(fields['Source Outlet']),
  sourceUrl: text(fields['Source URL']),
  sourcesCombined: text(fields['Sources Combined (for LLM)']),
  llmBlockFromSources: text(fields['LLM Block (from Article Sources)']),
  category,
  baadPublishCategories: fallbackCategories,
  newsTopic: text(fields['News Topic']),
  artistEntityNames: text(fields['Artist / Entity Name(s)']),
  artistCandidates: text(fields['Artist Candidates']),
  articleSourceIds: arr(fields['Article Sources']),
};
